import{_ as a,c as i,o as l,a1 as o}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"プラグイン紹介：機能とリスク | Antigravity Auth","description":"Antigravity Auth プラグインの中核的価値とリスクについて学びましょう。Google OAuth を通じて Claude と Gemini 3 モデルにアクセスし、マルチアカウント負荷分散をサポート。","frontmatter":{"title":"プラグイン紹介：機能とリスク | Antigravity Auth","sidebarTitle":"このプラグインはあなたに合っていますか","subtitle":"Antigravity Auth プラグインの中核的価値を理解する","description":"Antigravity Auth プラグインの中核的価値とリスクについて学びましょう。Google OAuth を通じて Claude と Gemini 3 モデルにアクセスし、マルチアカウント負荷分散をサポート。","tags":["入門","プラグイン紹介","OpenCode","Antigravity"],"order":1},"headers":[],"relativePath":"ja/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md","filePath":"ja/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"}'),e={name:"ja/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"};function r(n,t,s,h,d,u){return l(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="antigravity-auth-プラグインの中核的価値を理解する" tabindex="-1">Antigravity Auth プラグインの中核的価値を理解する <a class="header-anchor" href="#antigravity-auth-プラグインの中核的価値を理解する" aria-label="Permalink to &quot;Antigravity Auth プラグインの中核的価値を理解する&quot;">​</a></h1><p><strong>Antigravity Auth</strong> は OpenCode プラグインであり、Google OAuth 認証を通じて Antigravity API にアクセスします。Google アカウントで Claude Opus 4.5、Sonnet 4.5、Gemini 3 Pro/Flash などの高度なモデルを呼び出せ、API キー管理が不要です。プラグインはマルチアカウント負荷分散、デュアルクォータプール、自動セッション復元などの機能を提供し、高度なモデルと自動管理が必要なユーザーに適しています。</p><h2 id="学習後にできること" tabindex="-1">学習後にできること <a class="header-anchor" href="#学習後にできること" aria-label="Permalink to &quot;学習後にできること&quot;">​</a></h2><ul><li>このプラグインが使用シナリオに適合するか判断する</li><li>プラグインがサポートする AI モデルと中核機能を理解する</li><li>このプラグインの使用におけるリスクと注意事項を明確にする</li><li>インストールと設定を続行するか決定する</li></ul><h2 id="あなたが直面している課題" tabindex="-1">あなたが直面している課題 <a class="header-anchor" href="#あなたが直面している課題" aria-label="Permalink to &quot;あなたが直面している課題&quot;">​</a></h2><p>最先端の AI モデル（Claude Opus 4.5、Gemini 3 Pro など）を使用したいが、公式アクセスが制限されています。これらのモデルに確実にアクセスしつつ、以下を実現したいと考えています：</p><ul><li>複数の API キーを手動で管理する必要がない</li><li>レート制限時にアカウントを自動的に切り替えたい</li><li>会話の中断後に自動的に復元し、コンテキストを失わない</li></ul><h2 id="中核的なアプローチ" tabindex="-1">中核的なアプローチ <a class="header-anchor" href="#中核的なアプローチ" aria-label="Permalink to &quot;中核的なアプローチ&quot;">​</a></h2><p><strong>Antigravity Auth</strong> は OpenCode プラグインであり、<strong>Google OAuth 認証</strong> を通じて Google Antigravity API にアクセスし、Google アカウントで高度な AI モデルを呼び出せます。</p><p>これはすべてのリクエストをプロキシするのではなく、モデル呼び出しリクエストを<strong>インターセプトして変換</strong>し、Antigravity API に転送し、レスポンスを OpenCode が認識できる形式に変換します。</p><h2 id="主要な機能" tabindex="-1">主要な機能 <a class="header-anchor" href="#主要な機能" aria-label="Permalink to &quot;主要な機能&quot;">​</a></h2><h3 id="サポートされているモデル" tabindex="-1">サポートされているモデル <a class="header-anchor" href="#サポートされているモデル" aria-label="Permalink to &quot;サポートされているモデル&quot;">​</a></h3><table tabindex="0"><thead><tr><th>モデルシリーズ</th><th>利用可能なモデル</th><th>特徴</th></tr></thead><tbody><tr><td><strong>Claude</strong></td><td>Opus 4.5、Sonnet 4.5</td><td>拡張思考モードをサポート</td></tr><tr><td><strong>Gemini 3</strong></td><td>Pro、Flash</td><td>Google Search 統合、拡張思考</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Thinking モード</p><p>Thinking モデルは回答を生成する前に「深く考え」、推論プロセスを示します。思考予算を設定して、品質と応答速度のバランスを調整できます。</p></div><h3 id="マルチアカウント負荷分散" tabindex="-1">マルチアカウント負荷分散 <a class="header-anchor" href="#マルチアカウント負荷分散" aria-label="Permalink to &quot;マルチアカウント負荷分散&quot;">​</a></h3><ul><li><strong>最大 10 個の Google アカウント</strong> をサポート</li><li>レート制限（429 エラー）時に自動的に次のアカウントに切り替え</li><li>3 つのアカウント選択戦略：sticky（固定）、round-robin（ローテーション）、hybrid（インテリジェントハイブリッド）</li></ul><h3 id="デュアルクォータシステム" tabindex="-1">デュアルクォータシステム <a class="header-anchor" href="#デュアルクォータシステム" aria-label="Permalink to &quot;デュアルクォータシステム&quot;">​</a></h3><p>プラグインは<strong>2 つの独立したクォータプール</strong>に同時にアクセスします：</p><ol><li><strong>Antigravity クォータ</strong>：Google Antigravity API から</li><li><strong>Gemini CLI クォータ</strong>：Google Gemini CLI から</li></ol><p>1 つのプールがレート制限されると、プラグインは自動的に別のプールを試行し、クォータ使用率を最大化します。</p><h3 id="自動セッション復元" tabindex="-1">自動セッション復元 <a class="header-anchor" href="#自動セッション復元" aria-label="Permalink to &quot;自動セッション復元&quot;">​</a></h3><ul><li>ツール呼び出しの失敗を検出（ESC キーによる中断など）</li><li>自動的に synthetic tool_result を注入し、会話の崩壊を防ぐ</li><li>「continue」の自動送信による会話の継続をサポート</li></ul><h3 id="google-search-統合" tabindex="-1">Google Search 統合 <a class="header-anchor" href="#google-search-統合" aria-label="Permalink to &quot;Google Search 統合&quot;">​</a></h3><p>Gemini モデルでウェブ検索を有効化し、事実の正確性を向上：</p><ul><li><strong>Auto モード</strong>：モデルが必要に応じて検索するか判断</li><li><strong>Always-on モード</strong>：常に検索を実行</li></ul><h2 id="このプラグインの使用に適したシナリオ" tabindex="-1">このプラグインの使用に適したシナリオ <a class="header-anchor" href="#このプラグインの使用に適したシナリオ" aria-label="Permalink to &quot;このプラグインの使用に適したシナリオ&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">以下のシナリオに適しています</p><ul><li>複数の Google アカウントを持ち、総クォータを増やしたい</li><li>Claude または Gemini 3 の Thinking モデルを使用したい</li><li>Gemini モデルで Google Search を有効化したい</li><li>API キーを手動で管理したくなく、OAuth 認証に慣れている</li><li>頻繁にレート制限に遭遇し、アカウントの自動切り替えを望んでいる</li></ul></div><div class="warning custom-block"><p class="custom-block-title">以下のシナリオには適していません</p><ul><li>Google が公式に公開していないモデルを使用したい</li><li>Google ToS リスクに非常に敏感である（以下のリスク警告を参照）</li><li>基本的な Gemini 1.5 または Claude 3 モデルだけが必要（公式インターフェースの方が安定）</li><li>WSL、Docker などの環境でブラウザを開くのが困難である</li></ul></div><h2 id="⚠️-重要なリスク警告" tabindex="-1">⚠️ 重要なリスク警告 <a class="header-anchor" href="#⚠️-重要なリスク警告" aria-label="Permalink to &quot;⚠️ 重要なリスク警告&quot;">​</a></h2><p>このプラグインの使用は<strong>Google のサービス利用規約に違反する可能性があります</strong>。少数のユーザーが Google アカウントが<strong>停止</strong>または<strong>シャドウバン</strong>（明確な通知なしにアクセスが制限されること）されたと報告しています。</p><h3 id="高リスクシナリオ" tabindex="-1">高リスクシナリオ <a class="header-anchor" href="#高リスクシナリオ" aria-label="Permalink to &quot;高リスクシナリオ&quot;">​</a></h3><ul><li>🚨 <strong>新規 Google アカウント</strong>：停止される確率が非常に高い</li><li>🚨 <strong>最近 Pro/Ultra サブスクリプションを開始したアカウント</strong>：マークされて停止される可能性がある</li></ul><h3 id="使用前に確認してください" tabindex="-1">使用前に確認してください <a class="header-anchor" href="#使用前に確認してください" aria-label="Permalink to &quot;使用前に確認してください&quot;">​</a></h3><ul><li>これは<strong>非公式ツール</strong>であり、Google から承認されていない</li><li>アカウントが停止または永久にバンされる可能性がある</li><li>このプラグインの使用に関するすべてのリスクを自己責任で負う</li></ul><h3 id="推奨事項" tabindex="-1">推奨事項 <a class="header-anchor" href="#推奨事項" aria-label="Permalink to &quot;推奨事項&quot;">​</a></h3><ul><li>このプラグイン専用に<strong>新規アカウントを作成せず</strong>、成熟した Google アカウントを使用する</li><li>重要なサービスにリンクされた重要なアカウントの使用を避ける</li><li>アカウントが停止された場合、このプラグインを通じて異議申し立てはできない</li></ul><div class="danger custom-block"><p class="custom-block-title">アカウントセキュリティ</p><p>すべての OAuth トークンはローカルの <code>~/.config/opencode/antigravity-accounts.json</code> に保存され、いかなるサーバーにもアップロードされません。ただし、コンピュータのセキュリティを確保し、トークンの漏洩を防いでください。</p></div><h2 id="本レッスンのまとめ" tabindex="-1">本レッスンのまとめ <a class="header-anchor" href="#本レッスンのまとめ" aria-label="Permalink to &quot;本レッスンのまとめ&quot;">​</a></h2><p>Antigravity Auth は、Google OAuth を通じて Claude と Gemini 3 の高度なモデルにアクセスできる強力な OpenCode プラグインです。マルチアカウント負荷分散、デュアルクォータプール、自動セッション復元などの機能を提供し、高度なモデルと自動管理が必要なユーザーに適しています。</p><p>ただし、注意してください：<strong>このプラグインの使用にはアカウント停止のリスクがあります</strong>。重要でない Google アカウントを使用し、続行する前に関連するリスクを理解してください。</p><h2 id="次のレッスン" tabindex="-1">次のレッスン <a class="header-anchor" href="#次のレッスン" aria-label="Permalink to &quot;次のレッスン&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../../quick-install/">クイックインストール</a></strong> を学びます。</p><p>学べること：</p><ul><li>5 分でプラグインをインストール</li><li>最初の Google アカウントを追加</li><li>インストール成功を確認</li></ul></blockquote>',42)])])}const p=a(e,[["render",r]]);export{c as __pageData,p as default};
